    fbBuilder.addBool(6, PROPERTIES_IS_NULL);
    return fbBuilder.offset;
  }
  int addBboxOffset(int? offset) {
    fbBuilder.addOffset(7, offset);
    return fbBuilder.offset;
  }

  int finish() {
    return fbBuilder.endTable();
  }
}

class GJNFeatureObjectBuilder extends fb.ObjectBuilder {
  final String? _ID;
  final GJNGeometryObjectBuilder? _GEOMETRY;
  final List<GJNPropertyObjectBuilder>? _PROPERTIES;
  final double? _NUM_ID;
  final bool? _ID_IS_NUMERIC;
  final bool? _HAS_GEOMETRY;
  final bool? _PROPERTIES_IS_NULL;
  final GJNBoundingBoxObjectBuilder? _BBOX;

  GJNFeatureObjectBuilder({
    String? ID,
    GJNGeometryObjectBuilder? GEOMETRY,
    List<GJNPropertyObjectBuilder>? PROPERTIES,
    double? NUM_ID,
    double? numId,
    bool? ID_IS_NUMERIC,
    bool? idIsNumeric,
    bool? HAS_GEOMETRY,
    bool? hasGeometry,
    bool? PROPERTIES_IS_NULL,
    bool? propertiesIsNull,
    GJNBoundingBoxObjectBuilder? BBOX,
  })
      : _ID = ID,
        _GEOMETRY = GEOMETRY,
        _PROPERTIES = PROPERTIES,
        _NUM_ID = numId ?? NUM_ID,
        _ID_IS_NUMERIC = idIsNumeric ?? ID_IS_NUMERIC,
        _HAS_GEOMETRY = hasGeometry ?? HAS_GEOMETRY,
        _PROPERTIES_IS_NULL = propertiesIsNull ?? PROPERTIES_IS_NULL,
        _BBOX = BBOX;

  /// Finish building, and store into the [fbBuilder].
  @override
  int finish(fb.Builder fbBuilder) {
    final int? IDOffset = _ID == null ? null
        : fbBuilder.writeString(_ID!);
    final int? GEOMETRYOffset = _GEOMETRY?.getOrCreateOffset(fbBuilder);
    final int? PROPERTIESOffset = _PROPERTIES == null ? null
        : fbBuilder.writeList(_PROPERTIES!.map((b) => b.getOrCreateOffset(fbBuilder)).toList());
    final int? BBOXOffset = _BBOX?.getOrCreateOffset(fbBuilder);
    fbBuilder.startTable(8);
    fbBuilder.addOffset(0, IDOffset);
    fbBuilder.addOffset(1, GEOMETRYOffset);
    fbBuilder.addOffset(2, PROPERTIESOffset);
    fbBuilder.addFloat64(3, _NUM_ID);
    fbBuilder.addBool(4, _ID_IS_NUMERIC);
    fbBuilder.addBool(5, _HAS_GEOMETRY);
    fbBuilder.addBool(6, _PROPERTIES_IS_NULL);
    fbBuilder.addOffset(7, BBOXOffset);
    return fbBuilder.endTable();
  }

  /// Convenience method to serialize to byte list.
  @override
  Uint8List toBytes([String? fileIdentifier]) {
    final fbBuilder = fb.Builder(deduplicateTables: false);
    fbBuilder.finish(finish(fbBuilder), fileIdentifier);
    return fbBuilder.buffer;
  }
}
///  GeoJSON Bounding Box [west, south, east, north] or [west, south, min-alt, east, north, max-alt]
class GJNBoundingBox {
  GJNBoundingBox._(this._bc, this._bcOffset);
  factory GJNBoundingBox(List<int> bytes) {
    final rootRef = fb.BufferContext.fromBytes(bytes);
    return reader.read(rootRef, 0);
  }

  static const fb.Reader<GJNBoundingBox> reader = _GJNBoundingBoxReader();

  final fb.BufferContext _bc;
  final int _bcOffset;

  ///  Western longitude
  double get WEST => const fb.Float64Reader().vTableGet(_bc, _bcOffset, 4, 0.0);
  ///  Southern latitude
  double get SOUTH => const fb.Float64Reader().vTableGet(_bc, _bcOffset, 6, 0.0);
  ///  Eastern longitude
  double get EAST => const fb.Float64Reader().vTableGet(_bc, _bcOffset, 8, 0.0);
  ///  Northern latitude
  double get NORTH => const fb.Float64Reader().vTableGet(_bc, _bcOffset, 10, 0.0);
  ///  Minimum altitude (optional)
  double get MIN_ALTITUDE => const fb.Float64Reader().vTableGet(_bc, _bcOffset, 12, 0.0);
  double get minAltitude => MIN_ALTITUDE;
  ///  Maximum altitude (optional)
  double get MAX_ALTITUDE => const fb.Float64Reader().vTableGet(_bc, _bcOffset, 14, 0.0);
  double get maxAltitude => MAX_ALTITUDE;
  ///  True if the bbox includes altitude (6 values vs 4)
  bool get HAS_ALTITUDE => const fb.BoolReader().vTableGet(_bc, _bcOffset, 16, false);
  bool get hasAltitude => HAS_ALTITUDE;

  @override
  String toString() {
    return 'GJNBoundingBox{WEST: ${WEST}, SOUTH: ${SOUTH}, EAST: ${EAST}, NORTH: ${NORTH}, minAltitude: ${minAltitude}, maxAltitude: ${maxAltitude}, hasAltitude: ${hasAltitude}}';
  }
}

class _GJNBoundingBoxReader extends fb.TableReader<GJNBoundingBox> {
  const _GJNBoundingBoxReader();

  @override
  GJNBoundingBox createObject(fb.BufferContext bc, int offset) => 
    GJNBoundingBox._(bc, offset);
}

