///  GeoJSON FeatureCollection
class GJN {
  GJN._(this._bc, this._bcOffset);
  factory GJN(List<int> bytes) {
    final rootRef = fb.BufferContext.fromBytes(bytes);
    return reader.read(rootRef, 0);
  }

  static const fb.Reader<GJN> reader = _GJNReader();

  final fb.BufferContext _bc;
  final int _bcOffset;

  ///  Features in the collection
  List<GJNFeature>? get FEATURES => const fb.ListReader<GJNFeature>(GJNFeature.reader).vTableGetNullable(_bc, _bcOffset, 4);
  ///  Bounding box (optional)
  GJNBoundingBox? get BBOX => GJNBoundingBox.reader.vTableGetNullable(_bc, _bcOffset, 6);

  @override
  String toString() {
    return 'GJN{FEATURES: ${FEATURES}, BBOX: ${BBOX}}';
  }
}

class _GJNReader extends fb.TableReader<GJN> {
  const _GJNReader();

  @override
  GJN createObject(fb.BufferContext bc, int offset) => 
    GJN._(bc, offset);
}

